import React from 'react';

const AssetCard = ({ title, type, price }) => {
    return (
        <div className="asset-card">
            <h3>{title}</h3>
            <p className="type">{type}</p>
            <p className="price">{price}</p>
        </div>
    );
};

export default AssetCard;
